const Q_GEOGRAPHY_2010=[{"id": "objective>Geography>2010>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject are you doing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mathematics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CRK</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Economics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Geography</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question asks about the subject being done. Since the question is categorized under 'Geography', it is safe to assume that the subject being done is 'Geography'.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2010>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The feature marked <strong>M - N</strong> is a  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dissected plateau</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gorge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ridge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conical hill</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ridges are hard rocks cut by the side by high velocity rivers.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2010>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> The likely economic activity of the area is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mining</div>", "<div style=\"font-family:Cambria;font-size:17px;\">farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fishing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lumbering</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Farming is the major economic activity as a lot of scattered cultivation is found on the map.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2010>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> The drainage pattern on River Kuku is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rectangular </div>", "<div style=\"font-family:Cambria;font-size:17px;\">angular</div>", "<div style=\"font-family:Cambria;font-size:17px;\">centripetal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dendritic </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dendritic drainage pattern occurs like the branching of a tree</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2010>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> What is the direction of Gado from Pev?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">North east </div>", "<div style=\"font-family:Cambria;font-size:17px;\">North</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South east</div>", "<div style=\"font-family:Cambria;font-size:17px;\">North west</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the map, the direction of Gado from Pev is North West</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2010>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> On a topographical map, a number of inverted-V contours pointing up slope indicate a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">valley </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ridge</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saddle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spur</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Spurs are sharp ridges that intercept the upper course of a river. These are the most resistant part of the rock on the high velocity river path usually narrow in nature.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2010>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> What is the percentage of carbon monoxide in the atmosphere?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">49%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">51%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">45%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">47%</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Measure degree of 10 with your compass  <br/>  = 162<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>  <br/>  ∴ % of CO = 162/360 × 100  <br/>  = 45%.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2010>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The least of all the pollutants in the atmosphere is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrocarbons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen oxides</div>", "<div style=\"font-family:Cambria;font-size:17px;\">particles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur oxides</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The least of all the pollutants in the atmosphere is particles.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2010>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following items may not be necessary for a chain survey?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Arrow head </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gunter's chain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ranging pole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prismatic compass</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A prismatic compass may not be necessary for a chain survey as an arrow head, gunter's chain & ranging poles will be of more value for such.</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2010>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rocks can be classified into three major groups according to their </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">age and appearance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">origin and appearance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">age and origin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">origin and colour</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Origin explains how rocks were formed igneous versus sedimentary while appearance tells if stratified:- Sedimentary, Gramulates, Igneous, Colour etc.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2010>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a calcareous rock is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">granite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lignite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limestone</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Calcareous rocks are those that contain a high proportion of calcium carbonate. Limestone is a type of sedimentary rock that is primarily composed of calcium carbonate, making it an example of a calcareous rock.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2010>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main composition of coal is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carbon </div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clay </div>", "<div style=\"font-family:Cambria;font-size:17px;\">quarlz</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Coal is a black or brownish-black sedimentary rock that is primarily composed of carbon, along with various other elements such as hydrogen, sulfur, oxygen, and nitrogen. Therefore, the main composition of coal is carbon.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2010>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The feature marked F - F is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">thrust fault</div>", "<div style=\"font-family:Cambria;font-size:17px;\">normal fault</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reverse fault</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tear fault</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A normal fault occurs when a shift between plates occur without corresponding relatively remarked change in height.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2010>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The force that is primarily responsible for this type of process is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">compressional </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tensional</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kinetic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gravitational</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tensional forces resulting from stress could lead to normal fault.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2010>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A prominent erosional landform of wind action is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">seif</div>", "<div style=\"font-family:Cambria;font-size:17px;\">barchan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">playa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yardang</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A yardang is a streamlined, elongated, typically asymmetrical ridge in an arid region, carved and under cut by wind erosion. Yardangs become elongated features typically three or more times longer than wide, and when viewed from above, resemble the hull of a boat. Hence, it is a prominent erosional landform of wind action.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2010>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The column of ocean water moving from a low to a high latitude is described as a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cold ocean current </div>", "<div style=\"font-family:Cambria;font-size:17px;\">warm ocean current </div>", "<div style=\"font-family:Cambria;font-size:17px;\">coastal tidal wave </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cool ocean current</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Warm oceans currents are in areas of low pressure move to higher latitudes where they condense and form high pressure regions.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2010>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the temperature at sea level is 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C, what is the temperature of the air at a height of 2000 metres above sea level?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">11.2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">13.2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Environmental lapse rate = Non-rising air drops by 6.56<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C per 1 km/1000m rise in height  <br/> ∴ For 2000m → 6.5 × 2  <br/>  = 13<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C  <br/>  ∴ at sea level temperature = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C , <br/>  then at 2000m above sea level - 13<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C - 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C  = -3<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C.  <br/>  However, from the options this is not printed. So it is assumed that at sea level temperature was 0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C  <br/>  ∴ ≈ at 2000m = 13.2 <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2010>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When there is a remarkable difference between the date taken from the dry bulb and the wet bulb thermometer, it implies that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there is little water vapour in the air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is great cloudiness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the atmosphere is stable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation is no longer taking place</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dry bulb and wet bulb thermometer measures relative humidity. The lower the difference between the dry and wet bulb readings the more saturated the air mass is. However the more remarkable the difference in readings are, the lower the volume of water vapour in the air.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2010>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Iroko, Mahogany and Obeche trees are associated with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mediterranean woodland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Temperate coniferous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropical rainforest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropical savanna</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Iroko, Mahogany and Obeche trees are associated with the Tropical rainforest. These trees are native to the tropical rainforests of Africa and are known for their hardwood.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2010>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The zone which is rich in iron, aluminium, magnesium and clay substances is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Chorizon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dhorizon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ahorizon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bhorizon</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The B-horizon of a soil profile is usually rich in minerals such a Iron, Aluminium, Magnesium & Clay. A-horizon organic matter leached to the B-horizon layer.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2010>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a component of soil?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Structure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Texture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plasticity</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Texture, Structure and plasticity are all properties/characteristics of soil. However, water is one of the components that make up soil. Others include air, organic matter, etc.  <br/> Component of the soil includes inorganic matter, organic matter, soil water, soil air and living organism</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2010>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a non-renewable resource is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wind </div>", "<div style=\"font-family:Cambria;font-size:17px;\">water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">solar radiation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solid mineral</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wind, Water and Solar radiation are all renewable resources. However, solid minerals can be totally depleted and once depleted, cannot be replaced. </div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>2010>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main component of the land ecosystem are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lithosphere, biosphere, hydrosphere and atmosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vegetation, soil lithosphere and oceans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrosphere, atmosphere plants and animals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">river basin, biosphere, mountains and atmosphere</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Land ecosystem includes vegetation's, soil lithosphere and oceans. These encompasses both flora/fauna and their natural habitats.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2010>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An effect of global warming is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rise in the volume of ocean waters</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in atmosphere pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduction in green house emission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in cyclonic activities</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Global warming is an increase in mean temperature globally thus melting ice-caps of mountains and snow/icebergs at the poles leading to rise in the volume of ocean waters.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2010>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the population of an area is 690 million and the land area is 300,000km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>, the population density is approximately</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">230 persons per km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">240 persons per km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">210 persons per km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">220 persons per km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Population</td><td style=\"text-align:center;\">density</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">total population<hr size=\"1\" />land area</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">690,000,000<hr size=\"1\" />300,000</td></tr></table></div>  <br/>  = 2300 persons per km<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2010>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Migrant receiving regions tend to be characterised by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high per capita income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the predominance of females</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low per capital income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal sex ratio</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Higher per capita income means Higher national income per person in that country. Hence, higher standard of living and wealth in the destination of these migrants. </div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2010>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important impact of migration on population is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">environmental hazard</div>", "<div style=\"font-family:Cambria;font-size:17px;\">redistribution of the population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">even distribution the population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">environmental pollution</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Migration primarily affects the distribution of the population. People move from one place to another, which leads to a redistribution of the population. Therefore, the correct answer is option 2, 'redistribution of the population'.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2010>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The actual physical place a settlement occupies is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">situation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">site </div>", "<div style=\"font-family:Cambria;font-size:17px;\">community</div>", "<div style=\"font-family:Cambria;font-size:17px;\">society</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Site is the actual physical place a settlement occupies. Situation is the surrounding physical and anthropological circumstances around which the settlement is located (neighbouring descriptors).</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2010>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A town that is situated where two rivers meet is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">coastal town </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nodal town</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bridge town</div>", "<div style=\"font-family:Cambria;font-size:17px;\">confluence town</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Confluence towns are located where two rivers meet e.g Lokoja in Nigeria where River Niger and River Benue meet in Kogi State.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2010>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A settlement where social amenities are easily provided to the community is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">squatter settlement </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dispersed settlement </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Linear settlement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleated settlement</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Most urban/developed settlements are nucleated in nature. This is because social amenities are invested in such location to support the teaming population to ease mobility, use utilities (water, electricity etc), have access to health, financial & educational institutions with ease because of the high level of economic functions carried out by such settlements.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2010>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The growth of an industry largely depends on the size of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital </div>", "<div style=\"font-family:Cambria;font-size:17px;\">market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manpower</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">All production activities are carried out to meet the demand and devices of customers through sales. When demand increases, sales grows and when this happens, the industry concerned also expands and grows.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2010>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economic production is entirely based on </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Demand determines economic productions. Production includes all activities carried out to create utilities i.e to give satisfaction and meet the  desires of clients.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2010>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rise of Japan as an industrial nation owes much to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">her large population </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the relentless efforts of her government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the abundance of energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the cordial relationship with her neighbours</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Japan has a large population of skilled and highly educated people. This has been the brain behind her development in modern times. </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2010>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In developing countries, the most inhibiting factor for industrialization is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">multicultural economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monocultural economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capitalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diversified economy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monocultural economy implies that the economy of developing countries have hitherto be over-reliant on a major source of foriegn exchange earner or product for international trade e.g Crude oil being major source of GDP for Nigeria.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2010>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the shortest trade route linking Asia and Europe?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The Panama canal route</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Trans-Pacific route</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Suez canal route </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Thet Cape route</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Suez canal via Northern Egypt links Europe through the mediterranean sea end to Asia via the Indian ocean (Gulf of Aden) region.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2010>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In advanced countries of the world, a greater percentage of the working population is engaged in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tertiary activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">primary and secondary activities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">primary and tertiary activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary and tertiary activities</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Developed countries have more of their population in research and development, financial services, consulting, manufacturing etc. These are secondary and tertiary economic activities </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2010>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the leading industrial nations of the world ranking second in manufacturing output after the USA is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Russia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Germany </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Britain </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Japan</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As of this time, Japan was numbered second in manufacturing output behind USA. However, as of now, China has taken this position.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2010>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following best explains the reason for the decrease in the practice of bush fallowing in Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mechanized agricultural practice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The availability of agricultural inputs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rapid growth of population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lack of interest in crop production </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rapid population growth in Nigeria has placed great pressure on available  arable lands for alternative competing uses. Hence, the traditional practice of bush fallowing has seen a decrease overtime. </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2010>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A greater percentage of the population in Nigeria are engaged in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">public service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercial farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trading </div>", "<div style=\"font-family:Cambria;font-size:17px;\">subsistence farming</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Low scale/subsistence farming to provide just enough for immediate/extended family and a little extra for routine market sales is the dominant form of agriculture in Nigeria. Engaging a large portion of our population.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2010>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The population of Nigeria is estimated at </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">124 million people </div>", "<div style=\"font-family:Cambria;font-size:17px;\">96 million people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">162 million people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">140 million people</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In 2006, Nigeria's census gave a value of ≈ 140 million. However, by 2010 Nigeria's projected population ≈ 162 millions</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2010>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following regions of Nigeria has heights of up to 1500m above sea level?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">North Central Highland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Western Highland </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sokoto Plains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Eastern Scarpland</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The North Central Highlands spaning from Jos, Plateau, Zuma rock, down to Kano/Kaduna axis have heights of up to 1500m above sea level.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2010>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The intra-city movement of passengers in most Nigerian towns is largely by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rail</div>", "<div style=\"font-family:Cambria;font-size:17px;\">service buses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">taxis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">motorcycles</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Intra-city/ within city transport mode in most Nigerian cities are service buses. Taxis are for medium and high income dwellers, motorcycles limited to 1 passenger are for inner cities transport as they can not ply major roads stretching a good portion of road network in the cities while rail is still under developed for urban mass transit in most Nigerian cities.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2010>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a major problem affecting the development of the Southern coastlands of Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">poor soil fertility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oil pollution and spillage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ocean tides</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hilly terrain of the area</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Southern coastlands of Nigeria is home to the oil and gas industry of the country bedeviled by oil pollution and oil spillage which are regular occurences have as a result of oil exploration and exploitations.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2010>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An irrigation project in Nigeria devoted to sugarcane production cultivation is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pategi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bakolori</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Numan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shonga</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bakolori dam on River Sokoto in Sokoto State supports irrigation farming of sugar cane plantations across both sokoto and kebbi states. </div>", "topic": "REGIONAL GEOGRAPHY : IRRIGATION AGRICULTURE IN THE NILE AND NIGER BASIN"}, {"id": "objective>Geography>2010>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors mostly accounts for high population density in West African cities?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Efficient transportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Concentration of industries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Social amenities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Administrative capital</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Urban centres in West Africa usually have a relatively higher concentration of industries which serve as a strong pull factor for migrants. These cities were former colonial power houses for basic processing of agric-products for further export to colonial cities.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2010>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the equatorial region, most rainfall results from </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">convection effect </div>", "<div style=\"font-family:Cambria;font-size:17px;\">orographical effect</div>", "<div style=\"font-family:Cambria;font-size:17px;\">harmattan winds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cyclonic effect</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Conventions effect is a result of overheating of air masses to rise rapidly and condense to saturation leading to convectional rainfalls with thunderstorms. The Equatorial region with 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> sun position by Midday has the highest supply of solar radiation globally.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2010>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a major mineral resource found in South Africa?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Limestone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Natural gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Copper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gold</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">South Africa is known for its vast mineral resources, one of the most significant being gold. The country was once the world's largest gold producer, and gold remains a significant part of the South African economy. Therefore, gold is a major mineral resource found in South Africa.</div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2010>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the diagram below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> What is the major crop grown in the shaded area?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Groundnut</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cotton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maize </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Millet</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Senegambia region West Africa is renowned for its groundnut production </div>", "topic": "REGIONAL GEOGRAPHY : PLANTATION AGRICULTURE IN WEST AND EAST AFRICA"}, {"id": "objective>Geography>2010>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the diagram below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The river marked <strong>X</strong> is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">River Volta </div>", "<div style=\"font-family:Cambria;font-size:17px;\">River Sassandra</div>", "<div style=\"font-family:Cambria;font-size:17px;\">River Senagal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">River Gambia</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">River Sassandra is located in Cote d'Ivoire. Emptying into the Atlantic ocean down South of the country.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2010>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The highlands that provide the sources of River Niger are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Plateau of Southern Mali and North Central Plateu of Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Futa Djalon and Guinea Highlands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adamawa Highlands and Plateau of Southern Mali</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mandana Mountains and Plateau of Niger</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Futa Djalon and Guinea Highlands. All around the Guinea Conakry/Guinea Bissau region are reputable for being the source of the renowned River Nigeria which crosses a large number of West African countries terminating in the Niger-Delta region of Nigeria.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}];
